 document.addEventListener("submit",event=>{const form=event.target,id=form?.id;if(!["contractorForm","workerForm","visitorForm","investigationForm"].includes(id))return;const editId=form.dataset.editId||"",method=id==="contractorForm"?(editId?"updateContractor":"createContractor"):id==="workerForm"?(editId?"updateWorker":"createWorker"):id==="visitorForm"?"createVisitor":"createInvestigation";setTimeout(()=>{const item=id==="contractorForm"?data.contractors.find(x=>x.id===(editId||data.contractors.at(-1)?.id)):id==="workerForm"?data.workers.find(x=>x.id===(editId||data.workers.at(-1)?.id)):id==="visitorForm"?data.visitors.at(-1):data.investigations.at(-1);syncSystemEntity(method,item);},0);},true);
 document.addEventListener("click",event=>{const target=event.target.closest?.("[data-toggle-contractor],[data-toggle-worker],[data-checkout],[data-att-toggle]");if(!target)return;if(target.dataset.attToggle){const date=q("#attendanceDate")?.value||today(),permission=date===today()?"attendance.register":"attendance.edit";if(!window.GraviSupabase.canPermission(permission)){event.preventDefault();event.stopImmediatePropagation();toast("Tu perfil no permite modificar esta asistencia.");return;}}setTimeout(()=>{if(target.dataset.toggleContractor)syncSystemEntity("updateContractor",data.contractors.find(x=>x.id===target.dataset.toggleContractor));else if(target.dataset.toggleWorker)syncSystemEntity("updateWorker",data.workers.find(x=>x.id===target.dataset.toggleWorker));else if(target.dataset.checkout)syncSystemEntity("updateVisitor",data.visitors.find(x=>x.id===target.dataset.checkout));else if(target.dataset.attToggle){const date=q("#attendanceDate")?.value||today(),marks=data.attendance[attendanceKey(date)]||{},method=date===today()?"registerAttendance":"editAttendance";syncSystemEntity(method,{id:attendanceKey(date),workId:activeId,date,marks});}},0);},true);
