function renderBadge(w){const work=activeWork(),contractor=contractorName(w.contractorId),folio=`GVC-${String(workers().findIndex(x=>x.id===w.id)+1).padStart(4,"0")}`;const html=`<article class="badge-sheet"><header class="badge-head"><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>GAFETE DE IDENTIFICACIÓN</h1><small>${folio} · Rev. 02</small></header><div class="badge-photo">GVC</div><div class="badge-body"><h2>${esc(w.name)}</h2><div class="badge-data"><div><b>CARGO</b>${esc(w.position)}</div><div><b>CONTRATISTA</b>${esc(contractor)}</div><div><b>IMSS</b>${esc(w.nss)}</div><div><b>ALERGIA</b>${esc(w.allergies||"No especificada")}</div><div><b>TIPO DE SANGRE</b>${esc(w.bloodType||"No especificado")}</div><div><b>EN CASO DE ACCIDENTE</b>${esc(w.emergencyContact)} · ${esc(w.relationship)} · ${esc(w.emergencyPhone)}</div></div></div><footer class="badge-footer">Vigencia ${new Date().toLocaleString("es-MX",{month:"long",year:"numeric"})}<br>${esc(work.development)} · ${esc(work.name)}</footer></article>`;openSystemReport(html,{type:"badge",downloadName:"gafete",date:today(),worker:w,work});}

function renderVisitors(showForm=false){const canRegister=window.GraviSupabase.canPermission("visitors.register"),canEdit=window.GraviSupabase.canPermission("visitors.edit");q("#managementActions").innerHTML=canRegister?'<button class="primary" id="addVisitor" data-permission="visitors.register">+ Registrar visitante</button>':"";q("#addVisitor")?.addEventListener("click",()=>renderVisitors(true));const rows=visitors().filter(x=>x.date===today());q("#managementContent").innerHTML=`${showForm&&canRegister?visitorForm():""}<div class="data-panel"><h2>Visitantes de ${fmt(today())}</h2>${rows.length?`<table class="data-table"><thead><tr><th>Nombre</th><th>Empresa</th><th>Motivo / Persona</th><th>Entrada</th><th>Salida</th><th></th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.name)}</td><td>${esc(x.company)}</td><td>${esc(x.reason)}<br>${esc(x.visits)}</td><td>${esc(x.entry)}</td><td>${esc(x.exit||"En obra")}</td><td>${canEdit?`<button class="secondary" data-checkout="${x.id}" data-permission="visitors.edit" ${x.exit?"disabled":""}>Registrar salida</button>`:""}</td></tr>`).join("")}</tbody></table>`:'<div class="empty-management">Sin visitantes hoy.</div>'}</div>`;q("#visitorForm")?.addEventListener("submit",e=>{e.preventDefault();if(!window.GraviSupabase.canPermission("visitors.register"))return toast("Tu perfil no permite registrar visitantes.");const f=new FormData(e.currentTarget);data.visitors.push({id:uid(),workId:activeId,date:today(),name:f.get("name"),company:f.get("company"),reason:f.get("reason"),entry:f.get("entry"),exit:f.get("exit"),visits:f.get("visits"),notes:f.get("notes")});save();renderVisitors();});qa("[data-checkout]").forEach(b=>b.onclick=()=>{if(!window.GraviSupabase.canPermission("visitors.edit"))return toast("Tu perfil no permite editar visitantes.");const v=data.visitors.find(x=>x.id===b.dataset.checkout);v.exit=new Date().toTimeString().slice(0,5);save();renderVisitors();});}
function visitorForm(){const now=new Date().toTimeString().slice(0,5);return `<form id="visitorForm" class="modal-form" data-permission="visitors.register"><div class="visitor-grid"><label>Nombre completo<input name="name" required></label><label>Empresa<input name="company" required></label><label>Motivo de visita<input name="reason" required></label><label>Hora de entrada<input type="time" name="entry" value="${now}" required></label><label>Hora de salida<input type="time" name="exit"></label><label>Persona que visita<input name="visits" required></label><label>Observaciones<textarea name="notes" rows="2"></textarea></label></div><div class="form-footer"><button class="primary" data-permission="visitors.register">Guardar visitante</button></div></form>`;}

function attendanceKey(date){return `${activeId}|${date}`;}
function getWeekStart(dateStr){const d=new Date(`${dateStr}T12:00:00`),offset=(d.getDay()-5+7)%7;d.setDate(d.getDate()-offset);return d.toISOString().slice(0,10);}
function weekDays(start){const d=new Date(`${start}T12:00:00`);return Array.from({length:7},(_,i)=>{const x=new Date(d);x.setDate(d.getDate()+i);return x.toISOString().slice(0,10);});}
function weekDeadline(start){const d=new Date(`${start}T12:00:00`);d.setDate(d.getDate()+6);d.setHours(16,30,0,0);return d;}
function isWeekClosed(start){return new Date()>=weekDeadline(start);}
function presentCount(workId,date){const rec=data.attendance[`${workId}|${date}`]||{};return Object.values(rec).filter(x=>x==="P").length;}
function ensureClosedWeeks(){const keys=Object.keys(data.attendance).filter(k=>k.startsWith(`${activeId}|`));const starts=[...new Set(keys.map(k=>getWeekStart(k.split("|")[1])))];starts.forEach(start=>{if(isWeekClosed(start)&&!data.histories.some(h=>h.workId===activeId&&h.type==="attendance"&&h.weekStart===start)){data.histories.push({id:uid(),workId:activeId,type:"attendance",date:weekDays(start)[6],weekStart:start,createdAt:new Date().toISOString()});}});save();}
function attendanceGroups(staff,record){const groups=new Map();staff.forEach(worker=>{const contractor=contractorName(worker.contractorId)||"Sin contratista",key=normalized(contractor)||"sin-contratista";if(!groups.has(key))groups.set(key,{name:contractor,workers:[]});groups.get(key).workers.push(worker);});return [...groups.values()].sort((a,b)=>a.name.localeCompare(b.name,"es")).map(group=>{group.workers.sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"es"));group.present=group.workers.filter(worker=>record[worker.id]==="P").length;group.absent=group.workers.length-group.present;return group;});}
function ensureAttendanceDefaults(date,staff,closed){const key=attendanceKey(date);data.attendance[key]||={};let changed=false;if(!closed)staff.forEach(worker=>{if(!data.attendance[key][worker.id]){data.attendance[key][worker.id]="A";changed=true;}});if(changed)save();return data.attendance[key];}
function attendanceToggle(worker,status,current,closed){const active=current===status,label=status==="P"?"PRESENTE":"AUSENTE",kind=status==="P"?"present":"absent";return `<button type="button" class="attendance-toggle ${kind} ${active?"active":""}" data-att-toggle="${worker.id}" data-status="${status}" aria-pressed="${active}" ${closed?"disabled":""}>${label}</button>`;}
function renderAttendance(date=today()){const start=getWeekStart(date),days=weekDays(start),closed=isWeekClosed(start),staff=workers().filter(x=>x.status==="Activo"),record=ensureAttendanceDefaults(date,staff,closed),groups=attendanceGroups(staff,record),total=staff.length,present=staff.filter(worker=>record[worker.id]==="P").length,absent=total-present;q("#managementActions").innerHTML='<button class="secondary" id="weekPdf">Ver PDF semanal</button>';q("#weekPdf").onclick=()=>renderAttendanceReport(start);q("#managementContent").innerHTML=`${closed?'<div class="locked-banner">Semana cerrada. Los registros ya no pueden modificarse.</div>':""}<div class="data-panel attendance-panel"><div class="attendance-toolbar"><label>Fecha de captura<input id="attendanceDate" type="date" value="${date}"></label><span>Semana: ${fmt(start)} al ${fmt(days[6])}</span><span>Cierre: jueves 16:30</span></div>${staff.length?`<section class="attendance-summary"><article><b>${total}</b><span>Total trabajadores</span></article><article class="present"><b>${present}</b><span>Presentes</span></article><article class="absent"><b>${absent}</b><span>Ausentes</span></article></section><div class="attendance-contractor-list">${groups.map(group=>`<section class="attendance-contractor-card"><header><div><h3>${esc(group.name)}</h3><p>${group.workers.length} trabajadores</p></div><div class="attendance-contractor-stats"><span><b>${group.workers.length}</b>Total</span><span class="present"><b>${group.present}</b>Presentes</span><span class="absent"><b>${group.absent}</b>Ausentes</span></div></header><div class="attendance-worker-list">${group.workers.map(worker=>{const current=record[worker.id]||"A";return `<article class="attendance-worker-card ${current==="P"?"is-present":"is-absent"}"><div class="attendance-worker-info"><strong>${esc(worker.name)}</strong><small>${esc(worker.position||"Sin puesto")}</small></div><div class="attendance-actions">${attendanceToggle(worker,"A",current,closed)}${attendanceToggle(worker,"P",current,closed)}</div></article>`;}).join("")}</div></section>`).join("")}</div>`:'<div class="empty-management">Registra trabajadores activos para tomar asistencia.</div>'}</div>`;q("#attendanceDate").onchange=e=>renderAttendance(e.target.value);qa("[data-att-toggle]").forEach(button=>button.onclick=()=>{if(closed)return;data.attendance[attendanceKey(date)]||={};data.attendance[attendanceKey(date)][button.dataset.attToggle]=button.dataset.status;save();renderAttendance(date);});}
function renderAttendanceReport(start){const work=activeWork(),days=weekDays(start),staff=workers(),vs=visitors().filter(v=>days.includes(v.date));const rows=staff.map((w,i)=>`<tr><td>${i+1}</td><td>${esc(w.name)}</td><td>${esc(w.position)}</td><td>${esc(contractorName(w.contractorId))}</td>${days.map(d=>`<td>${esc(data.attendance[`${activeId}|${d}`]?.[w.id]||"-")}</td>`).join("")}</tr>`).join("");const html=`<article class="week-report"><div class="week-title"><b>GRAN VISIÓN CONSTRUCCIÓN · Rev. 02</b><h1>LISTA DE ASISTENCIA SEMANAL</h1><p>${esc(work.development)} · ${esc(work.name)} · ${fmt(start)} al ${fmt(days[6])}</p></div><table class="report-table"><thead><tr><th>No.</th><th>Nombre</th><th>Puesto</th><th>Compañía</th>${days.map(d=>`<th>${new Date(d+"T12:00").toLocaleDateString("es-MX",{weekday:"short"})}<br>${d.slice(5)}</th>`).join("")}</tr></thead><tbody>${rows}</tbody></table><div class="report-band">Visitantes</div><table class="report-table"><thead><tr><th>Nombre</th><th>Fecha</th><th>Entrada</th><th>Salida</th></tr></thead><tbody>${vs.map(v=>`<tr><td>${esc(v.name)}</td><td>${fmt(v.date)}</td><td>${esc(v.entry)}</td><td>${esc(v.exit||"-")}</td></tr>`).join("")||'<tr><td colspan="4">Sin visitantes</td></tr>'}</tbody></table></article>`;openSystemReport(html,{type:"attendance",downloadName:"asistencia-semanal",date:days[6],weekStart:start,workId:activeId});}

function renderWorkforce(){const date=today(),active=workers().filter(x=>x.status==="Activo"),present=active.filter(w=>data.attendance[attendanceKey(date)]?.[w.id]==="P"),vis=visitors().filter(v=>v.date===date&&!v.exit);const groups=contractors().map(c=>({name:c.name,count:present.filter(w=>w.contractorId===c.id).length})).filter(x=>x.count);q("#managementContent").innerHTML=`<div class="kpi-grid"><div class="kpi-card"><b>${present.length}</b><span>Trabajadores presentes</span></div><div class="kpi-card"><b>${vis.length}</b><span>Visitantes en obra</span></div><div class="kpi-card"><b>${present.length+vis.length}</b><span>Total general</span></div><div class="kpi-card"><b>${active.length}</b><span>Plantilla activa</span></div></div><div class="data-panel"><h2>Presentes por contratista</h2>${groups.length?`<table class="data-table">${groups.map(x=>`<tr><td>${esc(x.name)}</td><td><b>${x.count}</b></td></tr>`).join("")}</table>`:'<div class="empty-management">No hay asistencias marcadas hoy.</div>'}</div>`;}

function nextInvestigationFolio(){const year=new Date().getFullYear(),nums=data.investigations.map(x=>(x.folio||"").match(new RegExp(`^INV-${year}-(\\d+)$`))).filter(Boolean).map(x=>+x[1]);return `INV-${year}-${String((Math.max(0,...nums)+1)).padStart(4,"0")}`;}
function renderInvestigations(showForm=false,prefill=null){q("#managementActions").innerHTML='<button class="primary" id="addInvestigation">+ Nueva investigación</button>';q("#addInvestigation").onclick=()=>renderInvestigations(true);q("#managementContent").innerHTML=`${showForm?investigationForm(prefill):""}<div class="data-panel">${investigations().length?`<table class="data-table"><thead><tr><th>Folio</th><th>Fecha</th><th>Persona</th><th>Evento</th><th></th></tr></thead><tbody>${investigations().map(x=>`<tr><td>${x.folio}</td><td>${fmt(x.date)}</td><td>${esc(x.injuredName)}</td><td>${esc(x.description).slice(0,80)}</td><td><button class="secondary" data-open-investigation="${x.id}">Ver PDF</button></td></tr>`).join("")}</tbody></table>`:'<div class="empty-management">Sin investigaciones registradas.</div>'}</div>`;q("#investigationForm")?.addEventListener("submit",e=>{e.preventDefault();const f=new FormData(e.currentTarget),x={id:uid(),workId:activeId,folio:f.get("folio"),date:f.get("date"),time:f.get("time"),location:f.get("location"),injuredName:f.get("injuredName"),age:f.get("age"),position:f.get("position"),contractor:f.get("contractor"),supervisor:f.get("supervisor"),description:f.get("description"),injury:f.get("injury"),bodyPart:f.get("bodyPart"),immediateCare:f.get("immediateCare"),witnesses:f.get("witnesses"),causes:f.get("causes"),rootCause:f.get("rootCause"),correctiveActions:f.get("correctiveActions"),responsible:f.get("responsible"),dueDate:f.get("dueDate"),linkedIncidentFolio:f.get("linkedIncidentFolio"),createdAt:new Date().toISOString()};data.investigations.push(x);data.histories.push({id:uid(),workId:activeId,type:"investigation",date:x.date,investigationId:x.id});save();renderInvestigationReport(x);});qa("[data-open-investigation]").forEach(b=>b.onclick=()=>renderInvestigationReport(data.investigations.find(x=>x.id===b.dataset.openInvestigation)));}
function investigationForm(p={}){return `<form id="investigationForm" class="modal-form"><div class="investigation-sections"><label>Folio<input name="folio" value="${nextInvestigationFolio()}" readonly></label><label>Reporte relacionado<input name="linkedIncidentFolio" value="${esc(p.linkedIncidentFolio||"")}" readonly></label><label>Fecha<input name="date" type="date" value="${p.date||today()}" required></label><label>Hora<input name="time" type="time" value="${p.time||""}" required></label><label class="wide">Lugar<input name="location" value="${esc(p.location||activeWork()?.location||"")}" required></label><label>Persona accidentada<input name="injuredName" value="${esc(p.injuredName||"")}" required></label><label>Edad<input name="age" type="number" min="16" required></label><label>Puesto<input name="position" required></label><label>Contratista<input name="contractor" value="${esc(p.contractor||"")}" required></label><label>Supervisor<input name="supervisor" required></label><label class="wide">Descripción del accidente<textarea name="description" rows="4" required>${esc(p.description||"")}</textarea></label><label>Lesión<input name="injury" required></label><label>Parte del cuerpo<input name="bodyPart" required></label><label class="wide">Atención inmediata<textarea name="immediateCare" rows="3" required></textarea></label><label class="wide">Testigos<textarea name="witnesses" rows="3"></textarea></label><label class="wide">Causas identificadas<textarea name="causes" rows="3" required></textarea></label><label class="wide">Causa raíz<textarea name="rootCause" rows="3" required></textarea></label><label class="wide">Acciones correctivas<textarea name="correctiveActions" rows="3" required></textarea></label><label>Responsable<input name="responsible" required></label><label>Fecha compromiso<input name="dueDate" type="date" required></label></div><div class="form-footer"><button class="primary">Generar investigación</button></div></form>`;}
function renderInvestigationReport(x){const html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>INVESTIGACIÓN DE ACCIDENTE</h1></div><div><b>${x.folio}</b><br>Rev. 01</div></div><div class="report-meta equipment-meta"><div><b>FECHA / HORA</b>${fmt(x.date)} · ${x.time}</div><div><b>LUGAR</b>${esc(x.location)}</div><div><b>CONTRATISTA</b>${esc(x.contractor)}</div><div><b>PERSONA ACCIDENTADA</b>${esc(x.injuredName)}</div><div><b>PUESTO / EDAD</b>${esc(x.position)} · ${esc(x.age)}</div><div><b>SUPERVISOR</b>${esc(x.supervisor)}</div></div><div class="report-band">Descripción</div><div class="report-notes">${esc(x.description)}</div><div class="incident-report-section"><div><b>LESIÓN / PARTE DEL CUERPO</b>${esc(x.injury)} · ${esc(x.bodyPart)}</div><div><b>ATENCIÓN INMEDIATA</b>${esc(x.immediateCare)}</div><div><b>TESTIGOS</b>${esc(x.witnesses)}</div><div><b>CAUSAS IDENTIFICADAS</b>${esc(x.causes)}</div><div><b>CAUSA RAÍZ</b>${esc(x.rootCause)}</div><div><b>ACCIONES CORRECTIVAS</b>${esc(x.correctiveActions)}</div></div><div class="report-signatures"><div>${esc(x.responsible)}<br><b>RESPONSABLE</b></div><div>${fmt(x.dueDate)}<br><b>FECHA COMPROMISO</b></div><div>${esc(activeWork()?.name)}<br><b>OBRA</b></div></div>`;openSystemReport(html,{...x,type:"investigation",downloadName:"investigacion-accidente"});}
function bindIncidentInvestigation(){const radios=qa('[name="accidentOccurred"]');radios.forEach(r=>r.addEventListener("change",()=>{q("#createInvestigationButton").hidden=r.value!=="Sí"||!r.checked;}));q("#createInvestigationButton")?.addEventListener("click",()=>{if(typeof saveIncidentDraft==="function")saveIncidentDraft(true);const f=incidentForm.elements;pendingInvestigation={linkedIncidentFolio:f.folio.value,date:f.date.value,time:f.time.value,location:f.location.value,contractor:f.contractor.value,description:f.description.value,injuredName:f.involvedNames.value==="Sin personas involucradas"?"":f.involvedNames.value};openModule("investigations");renderInvestigations(true,pendingInvestigation);});}

function allDocuments(workId){const docs=[];let recs=[];try{recs=JSON.parse(localStorage.getItem("gvc-extintores-records-v1"))||[];}catch{}recs.filter(x=>(x.workId||"legacy")===workId).forEach(x=>docs.push({...x,source:"app"}));data.histories.filter(x=>x.workId===workId).forEach(x=>docs.push({...x,source:"system"}));return docs;}
function renderHistories(){const docs=allDocuments(activeId),groups={};docs.forEach(d=>{const key=d.type||"otros";(groups[key]||=[]).push(d);});q("#managementContent").innerHTML=Object.keys(groups).length?Object.entries(groups).map(([type,items])=>`<section class="history-group"><h2>${historyLabel(type)}</h2><div class="history-list">${items.sort((a,b)=>(b.date||"").localeCompare(a.date||"")).map(d=>`<article class="history-item"><div><h3>${fmt(d.date)||"Sin fecha"}</h3><p>${esc(d.folio||d.documentNumber||d.weekStart||d.status||"")}</p></div><div>${historyButton(d)}</div></article>`).join("")}</div></section>`).join(""):'<div class="empty-management">No hay documentos históricos en esta obra.</div>';qa("[data-open-week]").forEach(b=>b.onclick=()=>renderAttendanceReport(b.dataset.openWeek));qa("[data-open-inv]").forEach(b=>b.onclick=()=>renderInvestigationReport(data.investigations.find(x=>x.id===b.dataset.openInv)));if(typeof bindOpenButtons==="function")bindOpenButtons(q("#managementContent"));}
function historyLabel(t){return ({attendance:"Asistencia semanal",investigation:"Investigación de accidentes",incident:"Reporte diario de seguridad",extinguisher:"Inspección de extintores",firstAid:"Inspección de botiquín",tableSaw:"Sierra de banco",grinder:"Esmeril",extensionCord:"Extensión eléctrica"}[t]||t);}
function historyButton(d){if(d.type==="attendance")return `<button class="secondary" data-open-week="${d.weekStart}">Ver PDF</button>`;if(d.type==="investigation")return `<button class="secondary" data-open-inv="${d.investigationId}">Ver PDF</button>`;return `<button class="secondary" data-open="${d.id}">Ver reporte</button>`;}
function openSystemReport(html,payload){window.systemDownloadData=payload;q("#printReport").innerHTML=html;q("#editButton").hidden=true;displayView("reportView");}

// Compatibility layer for the document-management expansion. Existing storage keys
// and record shapes remain valid; new official fields are optional and additive.
const baseInit=init,baseRenderDashboard=renderDashboard,baseRenderWorkers=renderWorkers;
const baseRenderInvestigations=renderInvestigations,baseOpenSystemReport=openSystemReport;

function migrateExtendedData(){
  data.schemaVersion=Math.max(Number(data.schemaVersion)||1,2);
  data.works.forEach(w=>{w.costCenter??="";w.workOrder??="";w.front??="";w.partida??="";w.preparedBy??="";w.superintendent??="";});
  data.workers.forEach(w=>{w.admissionDate??="";w.newEntry??="No";w.workerClass??="Contratista";w.workshop??="No";w.photo??="";});
  save();
}
function bindExtendedWorkForm(){
  const form=q("#workForm");if(!form)return;
  q("#historyButton").onclick=()=>activeWork()?openModule("histories"):(renderWorks(),displayView("worksView"));
  form.onsubmit=e=>{e.preventDefault();const f=new FormData(form),work={id:uid(),development:f.get("development"),name:f.get("name"),location:f.get("location"),details:f.get("details"),costCenter:f.get("costCenter")||"",workOrder:f.get("workOrder")||"",front:f.get("front")||"",partida:f.get("partida")||"",preparedBy:f.get("preparedBy")||"",superintendent:f.get("superintendent")||"",createdAt:new Date().toISOString()};data.works.push(work);save();setActive(work.id);};
}
function syncIncidentInvestigationButton(){const selected=incidentForm.querySelector('[name="accidentOccurred"]:checked');q("#createInvestigationButton").hidden=selected?.value!=="Sí";}
function bindIncidentWorkerReuse(){const field=incidentForm?.elements?.involvedNames?.closest("label");if(!field||q("#incidentWorker"))return;field.insertAdjacentHTML("beforebegin",`<label class="wide">Trabajador registrado o captura manual<select id="incidentWorker"><option value="">Captura manual / persona no registrada</option>${workers().filter(w=>w.status==="Activo").map(w=>`<option value="${w.id}">${esc(w.name)} · ${esc(contractorName(w.contractorId))}</option>`).join("")}</select></label>`);q("#incidentWorker").addEventListener("change",e=>{const w=data.workers.find(x=>x.id===e.target.value);if(!w)return;incidentForm.elements.involvedNames.value=w.name;incidentForm.elements.positions.value=w.position;incidentForm.elements.contractor.value=contractorName(w.contractorId);incidentForm.elements.workerName.value=w.name;});q("#incidentButton")?.addEventListener("click",()=>setTimeout(syncIncidentInvestigationButton,0));q("#editButton")?.addEventListener("click",()=>setTimeout(syncIncidentInvestigationButton,0));syncIncidentInvestigationButton();}
function dashboardMetrics(){
  const recs=appRecords(),daily=recs.filter(x=>x.type==="incident"),inspections=recs.filter(x=>x.type!=="incident"),accidents=investigations().length;
  return [[presentCount(activeId,today()),"Trabajadores presentes",""],[contractors().filter(x=>x.status==="Activo").length,"Contratistas activos",""],[visitors().filter(x=>x.date===today()).length,"Visitantes del día",""],[allDocuments(activeId).length,"Reportes generados",""],[inspections.length,"Inspecciones realizadas",""],[accidents,"Accidentes registrados","alert"],[daily.filter(x=>x.accidentOccurred!=="Sí").length,"Incidentes registrados","alert"]];
}
renderDashboard=function(){baseRenderDashboard();const target=q("#dashboardKpis");if(target)target.innerHTML=dashboardMetrics().map(([value,label,kind])=>`<article class="dashboard-kpi ${kind}"><b>${value}</b><span>${label}</span></article>`).join("");};

function extendedWorkerFields(record=null){const options=(values,current)=>values.map(value=>`<option ${current===value?"selected":""}>${value}</option>`).join("");return `<label>Fecha de ingreso<input name="admissionDate" type="date" value="${esc(record?.admissionDate||"")}"></label><label>Nuevo ingreso<select name="newEntry">${options(["No","Sí"],record?.newEntry||"No")}</select></label><label>Clasificación<select name="workerClass">${options(["Contratista","Personal GRAVI","Personal técnico","Proyecto"],record?.workerClass||"Contratista")}</select></label><label>Taller / destajista<select name="workshop">${options(["No","Sí"],record?.workshop||"No")}</select></label><label class="worker-photo-input">Fotografía para gafete<input name="photo" type="file" accept="image/*"></label>`;}
renderWorkers=function(showForm=false,editId=""){
  baseRenderWorkers(showForm,editId);const form=q("#workerForm");if(!form)return;
  form.querySelector(".field-grid")?.insertAdjacentHTML("beforeend",extendedWorkerFields(editId?data.workers.find(item=>item.id===editId):null));
  form.addEventListener("submit",async e=>{const f=new FormData(e.currentTarget),worker=e.currentTarget.dataset.editId?data.workers.find(item=>item.id===e.currentTarget.dataset.editId):data.workers[data.workers.length-1];if(!worker||worker.workId!==activeId)return;worker.admissionDate=f.get("admissionDate")||worker.admissionDate||"";worker.newEntry=f.get("newEntry")||worker.newEntry||"No";worker.workerClass=f.get("workerClass")||worker.workerClass||"Contratista";worker.workshop=f.get("workshop")||worker.workshop||"No";const file=f.get("photo");if(file?.size&&typeof resizeImage==="function")worker.photo=await resizeImage(file);save();renderWorkers();});
};
function badgeFolio(w){if(!w.badgeFolio){const n=Math.max(0,...data.workers.map(x=>Number((x.badgeFolio||"").match(/(\d+)$/)?.[1])||0))+1;w.badgeFolio=`GVC-SEG-${String(n).padStart(4,"0")}`;save();}return w.badgeFolio;}
renderBadge=function(w){const work=activeWork(),contractor=contractorName(w.contractorId),folio=badgeFolio(w),issued=today(),validUntil=w.badgeValidUntil||new Date(new Date().setFullYear(new Date().getFullYear()+1)).toISOString().slice(0,10);const html=`<article class="badge-sheet"><header class="badge-head"><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>GAFETE DE IDENTIFICACIÓN</h1><small>FOLIO ${esc(folio)} · Rev. 02 · ACC. INSEG</small></header><div class="badge-photo">${w.photo?`<img src="${w.photo}" alt="Fotografía de ${esc(w.name)}">`:"GVC"}</div><div class="badge-body"><h2>${esc(w.name)}</h2><div class="badge-data"><div><b>CARGO</b>${esc(w.position)}</div><div><b>CONTRATISTA</b>${esc(contractor)}</div><div><b>IMSS</b>${esc(w.nss)}</div><div><b>ALERGIA</b>${esc(w.allergies||"No especificada")}</div><div><b>TIPO DE SANGRE</b>${esc(w.bloodType||"No especificado")}</div><div><b>EN CASO DE ACCIDENTE LLAMAR A</b>${esc(w.emergencyContact)} · ${esc(w.relationship)} · ${esc(w.emergencyPhone)}</div></div></div><div class="official-meta"><div><b>FECHA DE EMISIÓN</b>${fmt(issued)}</div><div><b>VIGENCIA</b>${fmt(validUntil)}</div></div><footer class="badge-footer">GVC-SEG-REG-039-F01<br>${esc(work.superintendent||"Sin superintendente asignado")} · SUPERINTENDENTE</footer></article>`;baseOpenSystemReport(html,{type:"badge",downloadName:"gafete",date:issued,code:"GVC-SEG-REG-039-F01",revision:"Rev. 02",worker:w,work});};

function attendanceSnapshot(start){const days=weekDays(start);return {work:{...activeWork()},days,workers:workers().map(w=>({...w,contractorName:contractorName(w.contractorId)})),attendance:Object.fromEntries(days.map(d=>[d,{...(data.attendance[`${activeId}|${d}`]||{})}])),visitors:visitors().filter(v=>days.includes(v.date)).map(v=>({...v})),generatedAt:new Date().toISOString()};}
ensureClosedWeeks=function(){const keys=Object.keys(data.attendance).filter(k=>k.startsWith(`${activeId}|`)),starts=[...new Set(keys.map(k=>getWeekStart(k.split("|")[1])))];starts.forEach(start=>{if(!isWeekClosed(start))return;let history=data.histories.find(h=>h.workId===activeId&&h.type==="attendance"&&h.weekStart===start);if(!history){history={id:uid(),workId:activeId,type:"attendance",date:weekDays(start)[6],weekStart:start,createdAt:new Date().toISOString(),documentVersion:2,snapshot:attendanceSnapshot(start)};data.histories.push(history);}else if(!history.snapshot){history.snapshot=attendanceSnapshot(start);history.documentVersion=2;}});save();};
renderAttendanceReport=function(start){const history=data.histories.find(h=>h.workId===activeId&&h.type==="attendance"&&h.weekStart===start),snap=history?.snapshot||attendanceSnapshot(start),work=snap.work,days=snap.days,staff=snap.workers,vs=snap.visitors,groups=new Map();staff.forEach(w=>{const key=w.contractorName||"Sin contratista";if(!groups.has(key))groups.set(key,[]);groups.get(key).push(w);});const sections=[...groups].map(([company,list])=>`<div class="attendance-contractor">${esc(company)} · ${list.length} trabajadores</div><table class="report-table"><thead><tr><th>No.</th><th>Nombre</th><th>Puesto</th><th>NSS</th><th>Ingreso</th><th>Nuevo</th><th>Taller</th>${days.map(d=>`<th>${new Date(d+"T12:00").toLocaleDateString("es-MX",{weekday:"short"})}<br>${d.slice(5)}</th>`).join("")}<th>Total</th></tr></thead><tbody>${list.map((w,i)=>{const marks=days.map(d=>snap.attendance[d]?.[w.id]||"-");return `<tr><td>${i+1}</td><td>${esc(w.name)}</td><td>${esc(w.position)}</td><td>${esc(w.nss)}</td><td>${fmt(w.admissionDate)}</td><td>${esc(w.newEntry||"No")}</td><td>${esc(w.workshop||"No")}</td>${marks.map(v=>`<td>${esc(v)}</td>`).join("")}<td>${marks.filter(v=>v==="P").length}</td></tr>`;}).join("")}</tbody></table>`).join("");const html=`<article class="week-report"><div class="week-title"><b>GRAN VISIÓN CONSTRUCCIÓN · Rev. 02</b><h1>LISTA DE ASISTENCIA SEMANAL</h1><p>${esc(work.development)} · ${esc(work.name)} · ${fmt(start)} al ${fmt(days[6])}</p></div><div class="official-meta"><div><b>ELABORÓ</b>${esc(work.preparedBy||"Sin asignar")}</div><div><b>LUGAR</b>${esc(work.location)}</div><div><b>OBRA / CENTRO DE COSTO</b>${esc(work.name)} / ${esc(work.costCenter||"-")}</div><div><b>OT / FRENTE / PARTIDA</b>${esc(work.workOrder||"-")} / ${esc(work.front||"-")} / ${esc(work.partida||"-")}</div></div>${sections||'<div class="report-notes">Sin trabajadores registrados.</div>'}<div class="report-band">Visitantes de la semana</div><table class="report-table"><thead><tr><th>Nombre</th><th>Empresa</th><th>Fecha</th><th>Entrada</th><th>Salida</th><th>Motivo / Persona visitada</th></tr></thead><tbody>${vs.map(v=>`<tr><td>${esc(v.name)}</td><td>${esc(v.company)}</td><td>${fmt(v.date)}</td><td>${esc(v.entry)}</td><td>${esc(v.exit||"-")}</td><td>${esc(v.reason)} · ${esc(v.visits)}</td></tr>`).join("")||'<tr><td colspan="6">Sin visitantes</td></tr>'}</tbody></table></article>`;baseOpenSystemReport(html,{type:"attendance",downloadName:"asistencia-semanal",date:days[6],weekStart:start,workId:activeId,code:"GVC-CON-REG-036-F11",revision:"Rev. 02",work});};

function augmentInvestigationForm(form){if(!form||form.dataset.extended)return;form.dataset.extended="1";const person=form.querySelector('[name="injuredName"]')?.closest("label");person?.insertAdjacentHTML("beforebegin",`<label>Trabajador registrado<select id="investigationWorker"><option value="">Captura manual</option>${workers().map(w=>`<option value="${w.id}">${esc(w.name)} · ${esc(contractorName(w.contractorId))}</option>`).join("")}</select></label>`);form.querySelector(".investigation-sections")?.insertAdjacentHTML("beforeend",`<div class="wide classification-grid"><label>Tipo de accidente<select name="accidentType"><option>Propio del trabajo</option><option>Tránsito</option><option>Trayecto</option><option>Deportivo</option><option>Violencia</option><option>Otro</option></select></label><label>Jornada<select name="workday"><option>Normal</option><option>Tiempo extra</option></select></label><label>Labor habitual<select name="usualWork"><option>Sí</option><option>No</option></select></label><label>Tiempo laborado previo<input name="hoursBefore" placeholder="Horas y minutos"></label><label>Lugar del accidente<select name="placeType"><option>Dentro de la obra</option><option>Fuera de la obra</option><option>Trayecto</option></select></label><label>¿Accidente mortal?<select name="fatal"><option>No</option><option>Sí</option></select></label><label>Tipo de lesión<input name="injuryType" placeholder="Fractura, herida, contusión..."></label><label>Agente del accidente<input name="accidentAgent" placeholder="Herramienta, material, equipo..."></label><label>Acto o condición insegura<input name="unsafeCondition"></label></div>`);q("#investigationWorker")?.addEventListener("change",e=>{const w=data.workers.find(x=>x.id===e.target.value);if(!w)return;form.elements.injuredName.value=w.name;form.elements.age.value=w.age;form.elements.position.value=w.position;form.elements.contractor.value=contractorName(w.contractorId);});form.addEventListener("submit",e=>{const f=new FormData(e.currentTarget),x=data.investigations[data.investigations.length-1];if(!x||x.workId!==activeId)return;Object.assign(x,{workerId:q("#investigationWorker")?.value||"",accidentType:f.get("accidentType"),workday:f.get("workday"),usualWork:f.get("usualWork"),hoursBefore:f.get("hoursBefore"),placeType:f.get("placeType"),fatal:f.get("fatal"),injuryType:f.get("injuryType"),accidentAgent:f.get("accidentAgent"),unsafeCondition:f.get("unsafeCondition")});save();renderInvestigationReport(x);});}
renderInvestigations=function(showForm=false,prefill=null){baseRenderInvestigations(showForm,prefill);augmentInvestigationForm(q("#investigationForm"));};
renderInvestigationReport=function(x){const html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>INVESTIGACIÓN DE ACCIDENTE</h1></div><div><b>${esc(x.folio)}</b><br>Rev. 01</div></div><div class="official-meta"><div><b>REPORTE RELACIONADO</b>${esc(x.linkedIncidentFolio||"-")}</div><div><b>FECHA / HORA</b>${fmt(x.date)} · ${esc(x.time)}</div><div><b>OBRA / LUGAR</b>${esc(activeWork()?.name)} · ${esc(x.location)}</div><div><b>CONTRATISTA</b>${esc(x.contractor)}</div></div><div class="report-meta equipment-meta"><div><b>PERSONA ACCIDENTADA</b>${esc(x.injuredName)}</div><div><b>PUESTO / EDAD</b>${esc(x.position)} · ${esc(x.age)}</div><div><b>SUPERVISOR</b>${esc(x.supervisor)}</div><div><b>TIPO / JORNADA</b>${esc(x.accidentType||"-")} · ${esc(x.workday||"-")}</div><div><b>LABOR HABITUAL / TIEMPO PREVIO</b>${esc(x.usualWork||"-")} · ${esc(x.hoursBefore||"-")}</div><div><b>LUGAR / MORTAL</b>${esc(x.placeType||"-")} · ${esc(x.fatal||"No")}</div></div><div class="report-band">Descripción del accidente</div><div class="report-notes">${esc(x.description)}</div><div class="incident-report-section"><div><b>LESIÓN / PARTE DEL CUERPO</b>${esc(x.injuryType||x.injury)} · ${esc(x.bodyPart)}</div><div><b>AGENTE DEL ACCIDENTE</b>${esc(x.accidentAgent||"No especificado")}</div><div><b>ACTO O CONDICIÓN INSEGURA</b>${esc(x.unsafeCondition||"No especificado")}</div><div><b>ATENCIÓN INMEDIATA</b>${esc(x.immediateCare)}</div><div><b>TESTIGOS</b>${esc(x.witnesses)}</div><div><b>CAUSAS IDENTIFICADAS</b>${esc(x.causes)}</div><div><b>CAUSA RAÍZ</b>${esc(x.rootCause)}</div><div><b>ACCIONES CORRECTIVAS</b>${esc(x.correctiveActions)}</div></div><div class="report-signatures"><div>${esc(x.responsible)}<br><b>RESPONSABLE</b></div><div>${fmt(x.dueDate)}<br><b>FECHA COMPROMISO</b></div><div>${esc(activeWork()?.superintendent||activeWork()?.name)}<br><b>SUPERINTENDENTE / OBRA</b></div></div>`;baseOpenSystemReport(html,{...x,type:"investigation",downloadName:"investigacion-accidente",code:"GVC-SSH-INV-001",revision:"Rev. 01",work:activeWork()});};

openSystemReport=function(html,payload){baseOpenSystemReport(html,payload);window.GvcDocuments?.decorate(q("#printReport"),payload);};
const phase1RenderDashboard=renderDashboard,phase1RenderWorkers=renderWorkers;
const phase1RenderContractors=renderContractors,phase1RenderInvestigations=renderInvestigations;
const phase1RenderInvestigationReport=renderInvestigationReport,phase1RenderBadge=renderBadge;

function migratePhase2Data(){
  data.schemaVersion=Math.max(Number(data.schemaVersion)||1,3);
  data.contractors.forEach(c=>{c.address??="";c.taxId??="";});
  data.workers.forEach(w=>{w.pieceworker??="No";w.birthDate??="";w.sex??="";w.address??="";w.occupationTime??="";});
  save();
}
renderBadge=function(worker){if(!worker.badgeValidUntil){const valid=new Date();valid.setFullYear(valid.getFullYear()+1);worker.badgeValidUntil=systemLocalDateISO(valid);save();}phase1RenderBadge(worker);};
function registerExtensionPoints(){
  const registry=window.GvcExtensions;if(!registry||registry.getModules().length)return;
  [["contractors","Contratistas"],["workers","Trabajadores"],["visitors","Visitantes"],["attendance","Asistencia"],["workforce","Fuerza laboral"],["incidents","Reportes diarios"],["inspections","Inspecciones"],["investigations","Investigaciones"]].forEach(([id,label])=>registry.registerModule({id,label,slot:"work-menu",status:"active"}));
  ["incident","attendance","investigation","extinguisher","firstAid","tableSaw","grinder","extensionCord","badge"].forEach(id=>registry.registerDocumentType({id,slot:"document-history",status:"active"}));
}

renderContractors=function(showForm=false,editId=""){phase1RenderContractors(showForm,editId);const form=q("#contractorForm");if(!form)return;const current=editId?data.contractors.find(item=>item.id===editId):null;form.querySelector(".field-grid")?.insertAdjacentHTML("beforeend",`<label class="wide">Domicilio<input name="address" value="${esc(current?.address||"")}"></label><label>RFC / identificación fiscal<input name="taxId" value="${esc(current?.taxId||"")}"></label>`);form.addEventListener("submit",e=>{const f=new FormData(e.currentTarget),contractor=e.currentTarget.dataset.editId?data.contractors.find(item=>item.id===e.currentTarget.dataset.editId):data.contractors[data.contractors.length-1];if(!contractor||contractor.workId!==activeId)return;contractor.address=f.get("address")||"";contractor.taxId=f.get("taxId")||"";save();renderContractors();});};

renderWorkers=function(showForm=false,editId=""){phase1RenderWorkers(showForm,editId);const form=q("#workerForm");if(!form)return;const current=editId?data.workers.find(item=>item.id===editId):null;form.querySelector(".field-grid")?.insertAdjacentHTML("beforeend",`<label>Fecha de nacimiento<input name="birthDate" type="date" value="${esc(current?.birthDate||"")}"></label><label>Sexo<select name="sex"><option value="">No especificado</option><option ${current?.sex==="Femenino"?"selected":""}>Femenino</option><option ${current?.sex==="Masculino"?"selected":""}>Masculino</option><option ${current?.sex==="Otro"?"selected":""}>Otro</option></select></label><label class="wide">Domicilio<input name="address" value="${esc(current?.address||"")}"></label><label>Antigüedad en la ocupación<input name="occupationTime" value="${esc(current?.occupationTime||"")}" placeholder="Ej. 2 años 4 meses"></label><label>Destajista<select name="pieceworker"><option ${current?.pieceworker!=="Sí"?"selected":""}>No</option><option ${current?.pieceworker==="Sí"?"selected":""}>Sí</option></select></label>`);form.addEventListener("submit",e=>{const f=new FormData(e.currentTarget),worker=e.currentTarget.dataset.editId?data.workers.find(item=>item.id===e.currentTarget.dataset.editId):data.workers[data.workers.length-1];if(!worker||worker.workId!==activeId)return;worker.birthDate=f.get("birthDate")||"";worker.sex=f.get("sex")||"";worker.address=f.get("address")||"";worker.occupationTime=f.get("occupationTime")||"";worker.pieceworker=f.get("pieceworker")||"No";save();renderWorkers();});};

function lastDays(count=7){const base=new Date(today()+"T12:00:00");return Array.from({length:count},(_,i)=>{const d=new Date(base);d.setDate(base.getDate()-(count-1-i));return d.toISOString().slice(0,10);});}
function renderDashboardInsights(){const target=q("#dashboardInsights");if(!target)return;const days=lastDays(),values=days.map(d=>presentCount(activeId,d)),max=Math.max(1,...values),recs=appRecords(),breakdown=[{label:"Reportes diarios",value:recs.filter(x=>x.type==="incident").length},{label:"Inspecciones",value:recs.filter(x=>x.type!=="incident").length},{label:"Investigaciones",value:investigations().length},{label:"Asistencias",value:data.histories.filter(x=>x.workId===activeId&&x.type==="attendance").length}],breakMax=Math.max(1,...breakdown.map(x=>x.value));target.innerHTML=`<article class="insight-card"><div class="insight-head"><div><h2>Presencia últimos 7 días</h2><p>Trabajadores marcados como presentes</p></div><span class="history-tag">Máx. ${max}</span></div><div class="trend-chart">${days.map((d,i)=>`<div class="trend-day"><div class="trend-bar" data-value="${values[i]}" style="height:${Math.max(4,values[i]/max*120)}px"></div><small>${new Date(d+"T12:00").toLocaleDateString("es-MX",{weekday:"short"})}</small></div>`).join("")}</div></article><article class="insight-card"><div class="insight-head"><div><h2>Actividad documental</h2><p>Distribución acumulada de la obra</p></div></div><div class="document-breakdown">${breakdown.map(x=>`<div class="breakdown-row"><span>${x.label}</span><div class="breakdown-track"><div class="breakdown-fill" style="width:${x.value/breakMax*100}%"></div></div><b>${x.value}</b></div>`).join("")}</div><div class="future-ready">Arquitectura modular GRAVI SST</div></article>`;}
renderDashboard=function(){phase1RenderDashboard();renderDashboardInsights();};

function attendanceSnapshotFor(workId,start){const previous=activeId;activeId=workId;try{return attendanceSnapshot(start);}finally{activeId=previous;}}
renderAttendanceReport=function(start){const history=data.histories.find(h=>h.workId===activeId&&h.type==="attendance"&&h.weekStart===start),snap=history?.snapshot||attendanceSnapshotFor(activeId,start),work=snap.work,days=snap.days,staff=snap.workers,vs=snap.visitors,groups=new Map();staff.forEach(w=>{const key=w.contractorName||"Sin contratista";if(!groups.has(key))groups.set(key,[]);groups.get(key).push(w);});const sections=[...groups].map(([company,list])=>`<div class="attendance-contractor">${esc(company)} · ${list.length} trabajadores</div><table class="report-table"><thead><tr><th>No.</th><th>Nombre</th><th>Puesto</th><th>NSS</th><th>Ingreso</th><th>Nuevo</th><th>Destajista</th><th>Taller</th>${days.map(d=>`<th>${new Date(d+"T12:00").toLocaleDateString("es-MX",{weekday:"short"})}<br>${d.slice(5)}</th>`).join("")}<th>Total</th></tr></thead><tbody>${list.map((w,i)=>{const marks=days.map(d=>snap.attendance[d]?.[w.id]||"-");return `<tr><td>${i+1}</td><td>${esc(w.name)}</td><td>${esc(w.position)}</td><td>${esc(w.nss)}</td><td>${fmt(w.admissionDate)}</td><td>${esc(w.newEntry||"No")}</td><td>${esc(w.pieceworker||"No")}</td><td>${esc(w.workshop||"No")}</td>${marks.map(v=>`<td>${esc(v)}</td>`).join("")}<td>${marks.filter(v=>v==="P").length}</td></tr>`;}).join("")}</tbody></table>`).join("");const html=`<article class="week-report"><div class="week-title"><b>GRAN VISIÓN CONSTRUCCIÓN · Rev. 02</b><h1>LISTA DE ASISTENCIA SEMANAL</h1><p>${esc(work.development)} · ${esc(work.name)} · ${fmt(start)} al ${fmt(days[6])}</p></div><div class="official-meta"><div><b>ELABORÓ</b>${esc(work.preparedBy||"Sin asignar")}</div><div><b>LUGAR</b>${esc(work.location)}</div><div><b>OBRA / CENTRO DE COSTO</b>${esc(work.name)} / ${esc(work.costCenter||"-")}</div><div><b>OT / FRENTE / PARTIDA</b>${esc(work.workOrder||"-")} / ${esc(work.front||"-")} / ${esc(work.partida||"-")}</div></div>${sections||'<div class="report-notes">Sin trabajadores registrados.</div>'}<div class="report-band">Visitantes de la semana</div><table class="report-table"><thead><tr><th>Nombre</th><th>Empresa</th><th>Fecha</th><th>Entrada</th><th>Salida</th><th>Motivo / Persona visitada</th></tr></thead><tbody>${vs.map(v=>`<tr><td>${esc(v.name)}</td><td>${esc(v.company)}</td><td>${fmt(v.date)}</td><td>${esc(v.entry)}</td><td>${esc(v.exit||"-")}</td><td>${esc(v.reason)} · ${esc(v.visits)}</td></tr>`).join("")||'<tr><td colspan="6">Sin visitantes</td></tr>'}</tbody></table></article>`;baseOpenSystemReport(html,{type:"attendance",downloadName:"asistencia-semanal",date:days[6],weekStart:start,workId:activeId,code:"GVC-CON-REG-036-F11",revision:"Rev. 02",work});};

function augmentPhase2Investigation(form){if(!form||form.dataset.officialComplete)return;form.dataset.officialComplete="1";form.querySelector(".investigation-sections")?.insertAdjacentHTML("beforeend",'<div class="wide classification-grid"><label>Fecha de nacimiento<input name="workerBirthDate" type="date"></label><label>Sexo<select name="workerSex"><option value="">No especificado</option><option>Femenino</option><option>Masculino</option><option>Otro</option></select></label><label>Domicilio del trabajador<input name="workerAddress"></label><label>Antigüedad en la ocupación<input name="occupationTime"></label><label>Turno habitual<select name="usualShift"><option>Diurno</option><option>Nocturno</option><option>Mixto</option><option>Por turnos</option></select></label><label>Día del accidente<input name="accidentWeekday" readonly></label></div>');q("#investigationWorker")?.addEventListener("change",e=>{const w=data.workers.find(x=>x.id===e.target.value);if(!w)return;form.elements.workerBirthDate.value=w.birthDate||"";form.elements.workerSex.value=w.sex||"";form.elements.workerAddress.value=w.address||"";form.elements.occupationTime.value=w.occupationTime||"";});form.elements.date?.addEventListener("change",()=>{form.elements.accidentWeekday.value=form.elements.date.value?new Date(form.elements.date.value+"T12:00").toLocaleDateString("es-MX",{weekday:"long"}):"";});if(form.elements.date)form.elements.date.dispatchEvent(new Event("change"));form.addEventListener("submit",e=>{const f=new FormData(e.currentTarget),x=data.investigations[data.investigations.length-1];if(!x||x.workId!==activeId)return;Object.assign(x,{workerBirthDate:f.get("workerBirthDate"),workerSex:f.get("workerSex"),workerAddress:f.get("workerAddress"),occupationTime:f.get("occupationTime"),usualShift:f.get("usualShift"),accidentWeekday:f.get("accidentWeekday")});save();renderInvestigationReport(x);});}
renderInvestigations=function(showForm=false,prefill=null){phase1RenderInvestigations(showForm,prefill);augmentPhase2Investigation(q("#investigationForm"));};
renderInvestigationReport=function(x){phase1RenderInvestigationReport(x);const report=q("#printReport"),worker=data.workers.find(w=>w.id===x.workerId),contractor=data.contractors.find(c=>c.id===worker?.contractorId),anchor=report.querySelector(".report-band");if(!anchor)return;anchor.insertAdjacentHTML("beforebegin",`<div class="official-meta"><div><b>NACIMIENTO / SEXO</b>${fmt(x.workerBirthDate||worker?.birthDate)} · ${esc(x.workerSex||worker?.sex||"-")}</div><div><b>DOMICILIO DEL TRABAJADOR</b>${esc(x.workerAddress||worker?.address||"-")}</div><div><b>ANTIGÜEDAD / TURNO</b>${esc(x.occupationTime||worker?.occupationTime||"-")} · ${esc(x.usualShift||"-")}</div><div><b>DÍA DEL ACCIDENTE</b>${esc(x.accidentWeekday||"-")}</div></div><div class="official-meta"><div><b>EMPLEADOR / CONTRATISTA</b>${esc(contractor?.name||x.contractor)}</div><div><b>RESPONSABLE</b>${esc(contractor?.responsible||"-")}</div><div><b>TELÉFONO / CORREO</b>${esc(contractor?.phone||"-")} · ${esc(contractor?.email||"-")}</div><div><b>DOMICILIO</b>${esc(contractor?.address||"-")}</div></div>`);window.GvcDocuments?.decorate(report,window.systemDownloadData||{});};

function documentsAcrossWorks(){return data.works.flatMap(work=>allDocuments(work.id).map(doc=>({...doc,workId:work.id,workName:work.name,development:work.development})));}
function documentDate(doc){return doc.date||doc.weekStart||doc.createdAt?.slice(0,10)||"";}
function documentFolio(doc){if(doc.folio)return doc.folio;if(doc.type==="investigation")return data.investigations.find(x=>x.id===doc.investigationId)?.folio||"";if(doc.type==="attendance")return `SEM-${doc.weekStart||documentDate(doc)}`;return doc.documentNumber||"";}
function documentContractor(doc){if(doc.type==="investigation")return data.investigations.find(x=>x.id===doc.investigationId)?.contractor||"";if(doc.type==="attendance")return [...new Set((doc.snapshot?.workers||[]).map(w=>w.contractorName).filter(Boolean))].join(", ");return doc.contractor||doc.fields?.contractor||"";}
function openFilteredDocument(doc){const previous=activeId;activeId=doc.workId;try{if(doc.type==="attendance")return renderAttendanceReport(doc.weekStart);if(doc.type==="investigation")return renderInvestigationReport(data.investigations.find(x=>x.id===doc.investigationId));currentRecord=doc;if(doc.type==="incident")renderIncidentReport(doc);else if(doc.type==="firstAid")renderFirstAidReport(doc);else if(equipmentConfigs[doc.type])renderEquipmentReport(doc);else renderReport(doc);showView("reportView");}finally{activeId=previous;}}
function historyFiltersMarkup(docs){const types=[...new Set(docs.map(d=>d.type||"otros"))].sort(),contractorNames=[...new Set([...data.contractors.map(c=>c.name),...docs.map(documentContractor)].filter(Boolean))].sort();return `<div class="history-filters"><label>Búsqueda rápida<input id="historySearch" type="search" placeholder="Folio, persona, obra o documento"></label><label>Obra<select id="historyWork"><option value="">Todas las obras</option>${data.works.map(w=>`<option value="${w.id}" ${w.id===activeId?"selected":""}>${esc(w.name)}</option>`).join("")}</select></label><label>Tipo de documento<select id="historyType"><option value="">Todos</option>${types.map(t=>`<option value="${esc(t)}">${esc(historyLabel(t))}</option>`).join("")}</select></label><label>Contratista<select id="historyContractor"><option value="">Todos</option>${contractorNames.map(name=>`<option>${esc(name)}</option>`).join("")}</select></label><label>Desde<input id="historyFrom" type="date"></label><label>Hasta<input id="historyTo" type="date"></label></div><div id="historyResults"></div>`;}
function bindHistoryFilters(docs){const render=()=>{const search=(q("#historySearch")?.value||"").toLowerCase(),work=q("#historyWork")?.value||"",type=q("#historyType")?.value||"",contractor=q("#historyContractor")?.value||"",from=q("#historyFrom")?.value||"",to=q("#historyTo")?.value||"";const filtered=docs.filter(d=>{const date=documentDate(d),contractorText=documentContractor(d),haystack=[documentFolio(d),d.weekStart,d.status,d.workName,d.development,historyLabel(d.type),contractorText,d.injuredName,d.description].filter(Boolean).join(" ").toLowerCase();return(!search||haystack.includes(search))&&(!work||d.workId===work)&&(!type||d.type===type)&&(!contractor||contractorText.includes(contractor))&&(!from||date>=from)&&(!to||date<=to);}).sort((a,b)=>documentDate(b).localeCompare(documentDate(a)));q("#historyResults").innerHTML=`<div class="history-results-head"><h2>Documentos</h2><span>${filtered.length} resultado${filtered.length===1?"":"s"}</span></div>${filtered.length?`<div class="history-list">${filtered.map((d,i)=>`<article class="history-item"><div><h3>${esc(historyLabel(d.type))}</h3><p>${fmt(documentDate(d))} · ${esc(documentFolio(d)||"Sin folio")}</p><div class="history-item-meta"><span class="history-tag">${esc(d.workName)}</span>${documentContractor(d)?`<span class="history-tag">${esc(documentContractor(d))}</span>`:""}</div></div><button class="secondary" data-filtered-doc="${i}">Abrir documento</button></article>`).join("")}</div>`:'<div class="empty-management">No hay documentos que coincidan con los filtros.</div>'}`;qa("[data-filtered-doc]").forEach(button=>button.onclick=()=>openFilteredDocument(filtered[Number(button.dataset.filteredDoc)]));};["#historySearch","#historyWork","#historyType","#historyContractor","#historyFrom","#historyTo"].forEach(selector=>q(selector)?.addEventListener(selector==="#historySearch"?"input":"change",render));render();}
