const phase4ComplianceStats=complianceStats,phase4BuildAlerts=buildAlerts,phase4RecentActivities=recentActivities,phase4OpenFilteredDocumentFinal=openFilteredDocument,phase4HistoryLabelFinal=historyLabel;

function criterionId(code,index){return `${code.replace(/[^0-9]/g,"")}-${String(index+1).padStart(2,"0")}`;}
function ensureOperationalCriteria(workId,code){const entry=ensureCompliance(workId).find(x=>x.code===code);entry.criteria||=nomCriteriaCatalog[code].map((label,index)=>({id:criterionId(code,index),label,status:"Sin revisión",reviewDate:"",responsible:"",evidence:[],observations:"",pendingAction:"",commitmentDate:"",updatedAt:""}));return entry.criteria;}
function calculateOperationalEntryStats(criteria=[]){
 const counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0,"Sin revisión":0};
 criteria.forEach(item=>{const status=Object.hasOwn(counts,item?.status)?item.status:"Sin revisión";counts[status]++;});
 const denominator=counts.Cumple+counts.Parcial+counts["No cumple"]+counts["Sin revisión"];
 const percentage=denominator?Math.round((counts.Cumple+counts.Parcial*.5)/denominator*100):0;
 const evaluated=counts.Cumple+counts.Parcial+counts["No cumple"];
 let status="Parcial";
 if(criteria.length>0&&counts["No aplica"]===criteria.length)status="No aplica";
 else if(evaluated===0&&counts["Sin revisión"]>0)status="Sin revisión";
 else if(percentage===100&&counts.Parcial===0&&counts["No cumple"]===0&&counts["Sin revisión"]===0)status="Cumple";
 else if(denominator>0&&counts["No cumple"]===denominator&&counts.Cumple===0&&counts.Parcial===0&&counts["Sin revisión"]===0)status="No cumple";
 return {percentage,status,counts};
}
function applyCriterionReviewStateV43(entry,criterionId,changes,audit={}){const item=entry.criteria.find(criterion=>criterion.id===criterionId);if(!item)throw new Error("Criterio no encontrado");const previousStatus=item.status;Object.assign(item,changes);const stats=calculateOperationalEntryStats(entry.criteria);Object.assign(entry,{operationalAligned:true,percentage:stats.percentage,status:stats.status,operationalCounts:stats.counts,updatedAt:changes.updatedAt});return {item,audit:{...audit,criterionId:item.id,criterionLabel:item.label,previousStatus,newStatus:item.status}};}
function operationalEntryStats(entry){return Array.isArray(entry?.criteria)?calculateOperationalEntryStats(entry.criteria):{percentage:Number(entry?.percentage)||0,status:entry?.status||"Sin revisión",counts:null};}
function refreshOperationalEntry(entry){const stats=operationalEntryStats({...entry,operationalAligned:true});entry.operationalAligned=true;entry.percentage=stats.percentage;entry.status=stats.status;entry.operationalCounts=stats.counts;entry.updatedAt=new Date().toISOString();return stats;}
function compactComplianceAuditV43(){data.complianceAudit=(data.complianceAudit||[]).map(audit=>{const evidence=Array.isArray(audit.evidence)?audit.evidence:[],base64Count=evidence.filter(item=>typeof item==="string"&&/^data:image\//i.test(item)).length;return {...audit,evidenceCount:Number.isFinite(Number(audit.evidenceCount))?Number(audit.evidenceCount):evidence.length,evidence:evidence.filter(item=>!(typeof item==="string"&&/^data:image\//i.test(item)))};}).sort((a,b)=>String(b.at||b.createdAt||"").localeCompare(String(a.at||a.createdAt||""))).slice(0,500);return data.complianceAudit;}
function migrateComplianceLocalV43(){if(data.complianceHotfixVersion==="v43")return;data.complianceAudit||=[];data.works.forEach(work=>nomDefinitions.forEach(([code])=>ensureOperationalCriteria(work.id,code).forEach(item=>{const hasAudit=data.complianceAudit.some(a=>a.workId===work.id&&a.nomCode===code&&a.criterionId===item.id);if(item.status==="No aplica"&&!item.reviewDate&&!item.responsible&&!item.observations&&!item.pendingAction&&!item.commitmentDate&&!item.updatedAt&&!hasAudit)item.status="Sin revisión";})));compactComplianceAuditV43();data.complianceHotfixVersion="v43";}
function migratePhase5Data(){data.schemaVersion=Math.max(Number(data.schemaVersion)||1,6);data.complianceAudit||=[];data.scheduledActivities||=[];data.works.forEach(work=>nomDefinitions.forEach(([code])=>ensureOperationalCriteria(work.id,code)));migrateComplianceLocalV43();save();}

complianceStats=function(workId){const base=phase4ComplianceStats(workId),entries=base.entries.map(entry=>{const stats=operationalEntryStats(entry);return {...entry,percentage:stats.percentage,status:stats.status,operationalCounts:stats.counts};}),applicable=entries.filter(x=>x.status!=="No aplica"),weights=applicable.map(x=>({value:x.percentage,weight:Math.max(1,(x.criteria||[]).filter(c=>c.status!=="No aplica").length)})),totalWeight=weights.reduce((sum,x)=>sum+x.weight,0),general=totalWeight?Math.round(weights.reduce((sum,x)=>sum+x.value*x.weight,0)/totalWeight):0,counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0,"Sin revisión":0};entries.forEach(x=>counts[x.status]=(counts[x.status]||0)+1);return {entries,applicable,general,risk:[...applicable].sort((a,b)=>a.percentage-b.percentage)[0]||null,pending:entries.filter(x=>["Parcial","No cumple","Sin revisión"].includes(x.status)).length,counts};};

openComplianceModule=function(){q("#managementTitle").textContent="Cumplimiento normativo";q("#managementSubtitle").textContent="Criterios verificables, evidencia y trazabilidad";q("#managementActions").innerHTML='<button class="secondary" id="scheduleActivities">Programación</button><button class="secondary" id="openMatrixFromCompliance">Matriz</button><button class="secondary" id="monthlyCompliance">Reporte mensual</button><button class="secondary" id="compliancePdf">Reporte general</button>';q("#scheduleActivities").onclick=()=>renderScheduleModule();q("#openMatrixFromCompliance").onclick=()=>openMatrixCompatibility();q("#monthlyCompliance").onclick=()=>createMonthlyComplianceDocument(activeId,currentMonthKey(),true);q("#compliancePdf").onclick=()=>createComplianceDocument();renderComplianceModule();displayView("managementView");markSidebar("compliance");};
renderComplianceModule=function(){const stats=complianceStats(activeId);q("#managementContent").innerHTML=`<div class="compliance-overview"><div class="compliance-score-card"><span>CUMPLIMIENTO GENERAL</span><strong>${stats.general}%</strong><span>${stats.applicable.length} NOM aplicables · ${stats.pending} con pendientes</span></div><div class="nom-management-grid">${stats.entries.map(entry=>`<article class="nom-card"><div class="nom-card-head"><h3>${entry.code}</h3><span class="nom-status">${esc(entry.status)}</span></div><p>${esc(entry.title)}</p><div class="nom-progress"><span class="${complianceClass(entry)}" style="width:${entry.percentage}%"></span></div><small>${entry.percentage}% · ${entry.criteria.length} criterios operativos</small><button class="secondary" data-open-criteria="${entry.code}">Administrar criterios</button></article>`).join("")}</div></div>`;qa("[data-open-criteria]").forEach(button=>button.onclick=()=>renderNomCriteria(button.dataset.openCriteria));};
function renderNomCriteria(code,editId=""){const entry=ensureCompliance(activeId).find(x=>x.code===code),criteria=ensureOperationalCriteria(activeId,code),stats=operationalEntryStats(entry),edit=criteria.find(x=>x.id===editId),audit=data.complianceAudit.filter(x=>x.workId===activeId&&x.nomCode===code).slice(0,20);q("#managementContent").innerHTML=`<div class="criteria-toolbar"><button class="back" id="criteriaBack">← Todas las NOM</button><div><h2>${entry.officialCode||entry.code}</h2><p>${esc(entry.title)} · ${stats.percentage}%</p></div></div>${edit?criterionForm(entry,edit):""}<div class="criteria-grid">${criteria.map(item=>`<article class="criterion-card status-${item.status.toLowerCase().replaceAll(" ","-")}"><div><span class="criterion-status">${esc(item.status)}</span><small>${fmt(item.reviewDate)||"Sin revisión"}</small></div><h3>${esc(item.label)}</h3><p>${esc(item.observations||"Sin observaciones")}</p><small>${esc(item.responsible||"Sin responsable")}</small><button class="secondary" data-edit-criterion="${item.id}">Revisar criterio</button></article>`).join("")}</div><section class="audit-panel"><h2>Historial de cumplimiento</h2>${audit.length?audit.map(a=>`<article class="audit-item"><time>${fmt(a.at.slice(0,10))} · ${a.at.slice(11,16)}</time><div><b>${esc(a.criterionLabel)}</b><span>${esc(a.previousStatus)} → ${esc(a.newStatus)}</span><p>${esc(a.comments||"Sin comentarios")}</p><small>${esc(a.user)}</small>${a.evidence?.length?`<div class="audit-evidence">${a.evidence.map(src=>`<img src="${src}" alt="Evidencia histórica">`).join("")}</div>`:""}</div></article>`).join(""):'<div class="empty-management">Aún no hay cambios registrados para esta NOM.</div>'}</section>`;q("#criteriaBack").onclick=renderComplianceModule;qa("[data-edit-criterion]").forEach(button=>button.onclick=()=>renderNomCriteria(code,button.dataset.editCriterion));q("#criterionForm")?.addEventListener("submit",saveCriterionReview);q("#cancelCriterion")?.addEventListener("click",()=>renderNomCriteria(code));}
function criterionForm(entry,item){const statuses=item.status==="Sin revisión"?["Sin revisión","Cumple","Parcial","No cumple","No aplica"]:["Cumple","Parcial","No cumple","No aplica"];return `<form id="criterionForm" class="modal-form criterion-form"><div class="section-title"><span>CR</span><div><h2>${esc(item.label)}</h2><p>${entry.code} · Registro auditable</p></div></div><input type="hidden" name="nomCode" value="${entry.code}"><input type="hidden" name="criterionId" value="${item.id}"><div class="field-grid"><label>Estado<select name="status" required>${statuses.map(value=>`<option ${item.status===value?"selected":""}>${value}</option>`).join("")}</select></label><label>Fecha de revisión<input name="reviewDate" type="date" value="${item.reviewDate||today()}" required></label><label class="wide">Responsable<input name="responsible" value="${esc(item.responsible)}" required></label><label class="wide">Observaciones<textarea name="observations" rows="3" required>${esc(item.observations)}</textarea></label><label class="wide">Acción pendiente<input name="pendingAction" value="${esc(item.pendingAction)}" placeholder="Medida correctiva o seguimiento"></label><label>Fecha compromiso<input name="commitmentDate" type="date" value="${item.commitmentDate||""}"></label><label class="wide">Evidencia<input name="evidence" type="file" accept="image/*" multiple disabled><small>Carga de evidencia temporalmente deshabilitada durante la estabilización del módulo. Las evidencias existentes se conservan.</small></label><label class="wide">Comentario del cambio<textarea name="changeComment" rows="2" required placeholder="Motivo o resultado de la revisión"></textarea></label></div><div class="form-footer"><button class="ghost" id="cancelCriterion" type="button">Cancelar</button><button class="primary">Guardar revisión</button></div></form>`;}
