function complianceUserIdentityV43(){const profile=window.GraviSupabase.getProfile(),user=window.GraviSupabase.getUser(),userName=profile?.full_name||user?.user_metadata?.full_name||user?.email||"Usuario GRAVI";return {userId:profile?.user_id||user?.id||null,userName,userRole:profile?.role||"",userEmail:user?.email||profile?.email||"",user:userName};}
