  const at=localDateTimeISO(),identity=complianceUserIdentityV43(),applied=applyCriterionReviewStateV43(entry,item.id,{status:f.get("status"),reviewDate,responsible:f.get("responsible"),observations:f.get("observations"),pendingAction:f.get("pendingAction"),commitmentDate:f.get("commitmentDate"),updatedAt:at},{id:uid(),workId,nomCode:entry.code,at,...identity,comments:f.get("changeComment"),evidenceCount:0,evidence:[]}),audit={...applied.audit,snapshot:{status:applied.item.status,reviewDate:applied.item.reviewDate,responsible:applied.item.responsible,observations:applied.item.observations,pendingAction:applied.item.pendingAction,commitmentDate:applied.item.commitmentDate}};
