function renderLegacyMigrationPanel52(){const panel=q("#legacyMigrationPanel"),legacy=data.works.find(isLegacyPlaceholder52),targets=data.works.filter(work=>!work.deletedAt&&!isLegacyPlaceholder52(work)),count=legacyRecordCount52();if(!legacy||!targets.length||!count){panel.hidden=true;panel.innerHTML="";return;}panel.hidden=false;panel.innerHTML=`<div class="legacy-migration-copy"><span class="legacy-migration-icon">!</span><div><h2 id="legacyMigrationTitle">Registros heredados pendientes de asignar</h2><p>Se encontraron <b>${count}</b> elementos anteriores al sistema por obras. Selecciona una obra real para fusionarlos; no se borrarán documentos ni se sobrescribirá información existente.</p></div></div><div class="legacy-migration-form"><label>Obra destino<select id="legacyTargetWork"><option value="">Selecciona una obra</option>${targets.map(work=>`<option value="${work.id}">${esc(work.development)} · ${esc(work.name)}</option>`).join("")}</select></label><button class="primary" id="migrateLegacyRecords" type="button">Asignar registros</button></div>`;q("#migrateLegacyRecords").onclick=()=>{const targetId=q("#legacyTargetWork").value;if(!targetId){toast("Selecciona la obra que recibirá los registros heredados.");q("#legacyTargetWork").focus();return;}migrateLegacyRecords52(targetId);};}
function migrateLegacyRecords52(targetId){const legacy=data.works.find(work=>isLegacyPlaceholder52(work)),target=data.works.find(work=>work.id===targetId&&!work.deletedAt&&!isLegacyPlaceholder52(work));if(!legacy||!target)return;const count=legacyRecordCount52();if(!confirm(`Se asignarán ${count} elementos heredados a ${target.development} · ${target.name}. Esta acción conservará los registros e historiales. ¿Continuar?`))return;let records=[];try{records=JSON.parse(localStorage.getItem("gvc-extintores-records-v1"))||[];}catch{}records.forEach(item=>{if((item.workId||"legacy")==="legacy")item.workId=targetId;});localStorage.setItem("gvc-extintores-records-v1",JSON.stringify(records));window.GraviSupabase?.syncRecords(records);["contractors","workers","visitors","histories","investigations","activity","complianceAudit"].forEach(key=>(data[key]||[]).forEach(item=>{if(item.workId==="legacy")item.workId=targetId;}));Object.keys(data.attendance||{}).filter(key=>key.startsWith("legacy|")).forEach(key=>{const date=key.slice(7),targetKey=`${targetId}|${date}`;data.attendance[targetKey]={...(data.attendance[key]||{}),...(data.attendance[targetKey]||{})};delete data.attendance[key];});data.scheduledActivities=(data.scheduledActivities||[]).filter(item=>item.workId!=="legacy");legacy.status="Migrada";legacy.migratedTo=targetId;legacy.migratedAt=new Date().toISOString();legacy.deletedAt=legacy.migratedAt;data.legacyMigrations||=[];data.legacyMigrations.unshift({id:uid(),fromWorkId:"legacy",toWorkId:targetId,count,createdAt:legacy.migratedAt,user:"Administrador GRAVI"});data.activity.unshift({id:uid(),workId:targetId,type:"migration",description:`${count} elementos heredados asignados desde Obra general`,user:"Administrador GRAVI",createdAt:legacy.migratedAt});save();localStorage.setItem(ACTIVE_KEY,targetId);localStorage.setItem(WORK_CONTEXT_KEY,"1");location.reload();}
function workersForWorks52(ids){return data.workers.filter(worker=>ids.includes(worker.workId)&&worker.status==="Activo").length;}
function contractorsForWorks52(ids){return data.contractors.filter(contractor=>ids.includes(contractor.workId)&&contractor.status==="Activo").length;}
function developmentGroups52(){const groups=new Map();(data.developments||[]).filter(item=>!item.deletedAt).forEach(item=>groups.set(item.name,{works:[],development:item}));navigableWorks52().forEach(work=>{const record=developmentRecord52(work.development),name=record?.name||work.development;if(!groups.has(name))groups.set(name,{works:[],development:record});groups.get(name).works.push(work);});return [...groups.entries()].map(([name,value])=>[name,value.works,value.development]).sort((a,b)=>a[0].localeCompare(b[0],"es"));}
function setBreadcrumb52(items){const root=q("#appBreadcrumb");root.innerHTML=items.map((item,index)=>`${index?'<span class="separator">›</span>':""}${item.action?`<button type="button" data-crumb="${index}">${esc(item.label)}</button>`:`<span>${esc(item.label)}</span>`}`).join("");qa("[data-crumb]",root).forEach(button=>button.onclick=items[Number(button.dataset.crumb)].action);}
