function workNavigationCard52(work){const ids=[work.id],status=(work.status||"Inactiva").toLowerCase(),legacy=isLegacyPlaceholder52(work);return `<article class="development-work-card ${legacy?"legacy-work-card":""}"><div class="development-work-head"><h2>${esc(work.name)}</h2><span class="work-status ${legacy?"inactive":status==="activa"?"active":status==="cerrada"?"closed":"inactive"}">${legacy?"HEREDADA":esc(work.status)}</span></div><p>${legacy?"Registros anteriores pendientes de asignar":esc(work.location)+(work.workNumber?` · ${esc(work.workNumber)}`:"")}</p><div class="development-work-stats"><span><b>${fmt(work.startDate)||"-"}</b>Inicio</span><span><b>${workersForWorks52(ids)}</b>Trabajadores</span><span><b>${contractorsForWorks52(ids)}</b>Contratistas</span></div><button class="primary" data-enter-work="${work.id}">Entrar a obra</button></article>`;}
