// Operational catalog polish: editable contractors/workers with logical status only.
function isActiveStatus(value){return String(value||"Activo").toLowerCase()==="activo";}
function normalizeOperationalCatalog(){let changed=false;data.contractors.forEach(c=>{if(!c.status){c.status="Activo";changed=true;}["name","responsible","phone","email","specialty"].forEach(key=>{if(c[key]===undefined){c[key]="";changed=true;}});});data.workers.forEach(w=>{if(!w.status){w.status="Activo";changed=true;}["name","position","phone","nss","contractorId"].forEach(key=>{if(w[key]===undefined){w[key]="";changed=true;}});});if(changed)save();}
function cleanFormValue(form,key){return String(new FormData(form).get(key)||"").trim();}
function statusClass(value){return isActiveStatus(value)?"status-active":"status-inactive";}
function contractorWorkerCounts(contractorId){const list=workers().filter(w=>w.contractorId===contractorId),active=list.filter(w=>isActiveStatus(w.status));return {total:list.length,active:active.length};}
function activeContractors(){return contractors().filter(c=>isActiveStatus(c.status));}
function setFormValues(form,record){if(!form||!record)return;Object.entries(record).forEach(([key,value])=>{const field=form.elements[key];if(!field)return;if(field.type==="file")return;field.value=value??"";});}
function contractorForm(record=null){return `<form id="contractorForm" class="modal-form" data-edit-id="${record?.id||""}"><div class="section-title"><span>${record?"ED":"+"}</span><div><h2>${record?"Editar contratista":"Nuevo contratista"}</h2><p>${record?"Actualiza datos sin perder historicos.":"Registra la empresa participante en esta obra."}</p></div></div><div class="field-grid"><label class="wide">Nombre del contratista<input name="name" required></label><label>Responsable<input name="responsible"></label><label>Telefono<input name="phone"></label><label>Correo<input name="email" type="email"></label><label class="wide">Especialidad o actividad<input name="specialty"></label><label>Estado<select name="status"><option>Activo</option><option>Inactivo</option></select></label><label class="wide">Domicilio<input name="address"></label><label>RFC / identificacion fiscal<input name="taxId"></label></div><div class="form-footer"><button class="ghost" type="button" data-cancel-contractor>Cancelar</button><button class="primary" type="submit">${record?"Guardar cambios":"Guardar contratista"}</button></div></form>`;}
renderContractors=function(showForm=false,editId=""){normalizeOperationalCatalog();const canAdmin=window.GraviSupabase?.canPermission?.("contractors.create")!==false;q("#managementActions").innerHTML=canAdmin?'<button class="primary" id="addContractor">+ Contratista</button>':"";q("#addContractor")?.addEventListener("click",()=>renderContractors(true));const rows=contractors().sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"es")),editing=editId?data.contractors.find(x=>x.id===editId):null;q("#managementContent").innerHTML=`${showForm?contractorForm(editing):""}<div class="data-panel"><div class="panel-heading-inline"><h2>Contratistas de la obra</h2><span>${rows.filter(x=>isActiveStatus(x.status)).length} activos / ${rows.length} totales</span></div>${rows.length?`<table class="data-table"><thead><tr><th>Contratista</th><th>Responsable</th><th>Especialidad</th><th>Contacto</th><th>Trabajadores</th><th>Estado</th><th></th></tr></thead><tbody>${rows.map(x=>{const count=contractorWorkerCounts(x.id);return `<tr><td><b>${esc(x.name)}</b>${x.address?`<br><small>${esc(x.address)}</small>`:""}</td><td>${esc(x.responsible||"-")}</td><td>${esc(x.specialty||"-")}</td><td>${esc(x.phone||"-")}<br>${esc(x.email||"")}</td><td>${count.total}<br><small>${count.active} activos</small></td><td class="${statusClass(x.status)}">${esc(x.status)}</td><td class="actions"><div class="inline-actions"><button class="secondary" data-edit-contractor="${x.id}">Editar</button><button class="secondary" data-toggle-contractor="${x.id}">${isActiveStatus(x.status)?"Inactivar":"Activar"}</button></div></td></tr>`;}).join("")}</tbody></table>`:'<div class="empty-management">Sin contratistas registrados.</div>'}</div>`;const form=q("#contractorForm");if(form){setFormValues(form,editing);form.addEventListener("submit",event=>{event.preventDefault();const name=cleanFormValue(form,"name");if(!name)return toast("El nombre del contratista es obligatorio.");const f=new FormData(form),payload={name,responsible:cleanFormValue(form,"responsible"),phone:cleanFormValue(form,"phone"),email:cleanFormValue(form,"email"),specialty:cleanFormValue(form,"specialty"),status:f.get("status")||"Activo",address:cleanFormValue(form,"address"),taxId:cleanFormValue(form,"taxId"),updatedAt:new Date().toISOString()};if(editing)Object.assign(editing,payload);else data.contractors.push({id:uid(),workId:activeId,createdAt:new Date().toISOString(),...payload});save();renderContractors();toast(editing?"Contratista actualizado correctamente.":"Contratista guardado correctamente.");});q("[data-cancel-contractor]")?.addEventListener("click",()=>renderContractors());}qa("[data-edit-contractor]").forEach(button=>button.onclick=()=>renderContractors(true,button.dataset.editContractor));qa("[data-toggle-contractor]").forEach(button=>button.onclick=()=>{const contractor=data.contractors.find(x=>x.id===button.dataset.toggleContractor);if(!contractor)return;contractor.status=isActiveStatus(contractor.status)?"Inactivo":"Activo";contractor.updatedAt=new Date().toISOString();save();renderContractors();toast(`Contratista ${contractor.status.toLowerCase()} correctamente.`);});};
function workerStatusOptions(current="Activo"){return ["Activo","Inactivo","Baja"].map(status=>`<option ${status===current?"selected":""}>${status}</option>`).join("");}
function contractorOptionsForWorker(worker=null){const selected=worker?.contractorId||"",options=activeContractors().map(c=>`<option value="${c.id}" ${c.id===selected?"selected":""}>${esc(c.name)}</option>`);if(selected&&!activeContractors().some(c=>c.id===selected)){const c=data.contractors.find(x=>x.id===selected);if(c)options.unshift(`<option value="${c.id}" selected>${esc(c.name)} (inactivo)</option>`);}return options.join("");}
function workerForm(record=null){return `<form id="workerForm" class="modal-form" data-edit-id="${record?.id||""}"><div class="section-title"><span>${record?"ED":"+"}</span><div><h2>${record?"Editar trabajador":"Nuevo trabajador"}</h2><p>${record?"Puedes cambiar contratista, puesto y estado sin afectar historicos.":"Solo se muestran contratistas activos como opcion principal."}</p></div></div><div class="field-grid"><label class="wide">Nombre completo<input name="name" required></label><label>Edad<input name="age" type="number" min="16"></label><label>NSS / identificacion<input name="nss"></label><label>Puesto<input name="position" required></label><label>Contratista<select name="contractorId" required><option value="">Selecciona</option>${contractorOptionsForWorker(record)}</select></label><label>Telefono<input name="phone"></label><label>Estado<select name="status">${workerStatusOptions(record?.status||"Activo")}</select></label><label>Fecha de ingreso<input name="admissionDate" type="date"></label><label>Nuevo ingreso<select name="newEntry"><option>No</option><option>Si</option></select></label><label>Clasificacion<select name="workerClass"><option>Contratista</option><option>Personal GRAVI</option><option>Personal tecnico</option><option>Proyecto</option></select></label><label>Taller / destajista<select name="workshop"><option>No</option><option>Si</option></select></label><label>Fecha de nacimiento<input name="birthDate" type="date"></label><label>Sexo<select name="sex"><option value="">No especificado</option><option>Femenino</option><option>Masculino</option><option>Otro</option></select></label><label class="wide">Domicilio<input name="address"></label><label>Antiguedad en la ocupacion<input name="occupationTime" placeholder="Ej. 2 anos 4 meses"></label><label>Destajista<select name="pieceworker"><option>No</option><option>Si</option></select></label><label>Contacto de emergencia<input name="emergencyContact"></label><label>Parentesco<input name="relationship"></label><label>Telefono de emergencia<input name="emergencyPhone"></label><label>Tipo de sangre<input name="bloodType"></label><label>Alergias<input name="allergies"></label><label class="worker-photo-input">Fotografia para gafete<input name="photo" type="file" accept="image/*"></label></div><div class="form-footer"><button class="ghost" type="button" data-cancel-worker>Cancelar</button><button class="primary" type="submit">${record?"Guardar cambios":"Guardar trabajador"}</button></div></form>`;}
function workerRow(worker){return `<tr><td><b>${esc(worker.name)}</b>${worker.age?`<br><small>${esc(worker.age)} anos</small>`:""}</td><td>${esc(worker.position||"-")}</td><td>${esc(worker.nss||"-")}</td><td>${esc(worker.phone||"-")}</td><td>${esc(worker.emergencyContact||"-")}<br>${esc(worker.emergencyPhone||"")}</td><td class="${statusClass(worker.status)}">${esc(worker.status)}</td><td class="actions"><div class="inline-actions"><button class="secondary" data-badge="${worker.id}">Gafete</button><button class="secondary" data-edit-worker="${worker.id}">Editar</button><button class="secondary" data-worker-status="${worker.id}" data-status="Activo">Activar</button><button class="secondary" data-worker-status="${worker.id}" data-status="Inactivo">Inactivar</button><button class="secondary" data-worker-status="${worker.id}" data-status="Baja">Baja</button></div></td></tr>`;}
function groupedWorkersMarkup(rows){const groups=new Map();rows.forEach(worker=>{const key=worker.contractorId||"none";if(!groups.has(key))groups.set(key,{contractor:data.contractors.find(c=>c.id===worker.contractorId),workers:[]});groups.get(key).workers.push(worker);});return [...groups.values()].sort((a,b)=>String(a.contractor?.name||"Sin contratista").localeCompare(String(b.contractor?.name||"Sin contratista"),"es")).map(group=>{const title=group.contractor?.name||"Sin contratista",active=group.workers.filter(w=>isActiveStatus(w.status)).length;return `<details class="worker-group" open><summary><span>${esc(title)}</span><b>${group.workers.length} trabajadores</b><small>${active} activos</small></summary><div class="worker-group-table"><table class="data-table"><thead><tr><th>Nombre</th><th>Puesto</th><th>NSS / ID</th><th>Telefono</th><th>Emergencia</th><th>Estado</th><th></th></tr></thead><tbody>${group.workers.sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"es")).map(workerRow).join("")}</tbody></table></div></details>`;}).join("");}
renderWorkers=function(showForm=false,editId=""){normalizeOperationalCatalog();q("#managementActions").innerHTML='<button class="primary" id="addWorker">+ Trabajador</button>';q("#addWorker")?.addEventListener("click",()=>renderWorkers(true));const rows=workers(),editing=editId?data.workers.find(x=>x.id===editId):null,activeCount=rows.filter(w=>isActiveStatus(w.status)).length;q("#managementContent").innerHTML=`${showForm?workerForm(editing):""}<div class="data-panel"><div class="panel-heading-inline"><h2>Trabajadores por contratista</h2><span>${activeCount} activos / ${rows.length} totales</span></div>${rows.length?groupedWorkersMarkup(rows):'<div class="empty-management">Sin trabajadores registrados.</div>'}</div>`;const form=q("#workerForm");if(form){setFormValues(form,editing);form.addEventListener("submit",async event=>{event.preventDefault();const name=cleanFormValue(form,"name"),contractorId=cleanFormValue(form,"contractorId");if(!name)return toast("El nombre del trabajador es obligatorio.");if(!contractorId)return toast("Selecciona un contratista para el trabajador.");const f=new FormData(form),payload={name,contractorId,age:cleanFormValue(form,"age"),nss:cleanFormValue(form,"nss"),position:cleanFormValue(form,"position"),phone:cleanFormValue(form,"phone"),emergencyContact:cleanFormValue(form,"emergencyContact"),relationship:cleanFormValue(form,"relationship"),emergencyPhone:cleanFormValue(form,"emergencyPhone"),bloodType:cleanFormValue(form,"bloodType"),allergies:cleanFormValue(form,"allergies"),status:f.get("status")||"Activo",admissionDate:cleanFormValue(form,"admissionDate"),newEntry:f.get("newEntry")||"No",workerClass:f.get("workerClass")||"Contratista",workshop:f.get("workshop")||"No",birthDate:cleanFormValue(form,"birthDate"),sex:f.get("sex")||"",address:cleanFormValue(form,"address"),occupationTime:cleanFormValue(form,"occupationTime"),pieceworker:f.get("pieceworker")||"No",updatedAt:new Date().toISOString()};const file=f.get("photo");if(file?.size&&typeof resizeImage==="function")payload.photo=await resizeImage(file);else if(editing?.photo)payload.photo=editing.photo;if(editing)Object.assign(editing,payload);else data.workers.push({id:uid(),workId:activeId,createdAt:new Date().toISOString(),...payload});save();renderWorkers();toast(editing?"Trabajador actualizado correctamente.":"Trabajador guardado correctamente.");});q("[data-cancel-worker]")?.addEventListener("click",()=>renderWorkers());}qa("[data-edit-worker]").forEach(button=>button.onclick=()=>renderWorkers(true,button.dataset.editWorker));qa("[data-worker-status]").forEach(button=>button.onclick=()=>{const worker=data.workers.find(x=>x.id===button.dataset.workerStatus);if(!worker)return;worker.status=button.dataset.status;worker.updatedAt=new Date().toISOString();save();renderWorkers();toast(`Trabajador marcado como ${worker.status.toLowerCase()}.`);});qa("[data-badge]").forEach(button=>button.onclick=()=>renderBadge(data.workers.find(x=>x.id===button.dataset.badge)));};
const basePresentCountOperational=presentCount;
presentCount=function(workId,date){const activeWorkerIds=new Set(data.workers.filter(worker=>worker.workId===workId&&isActiveStatus(worker.status)).map(worker=>worker.id)),rec=data.attendance[`${workId}|${date}`]||{};return Object.entries(rec).filter(([workerId,status])=>status==="P"&&activeWorkerIds.has(workerId)).length;};

// Operational traceability, search and readability polish.
function auditUser(){const profile=window.GraviSupabase?.getProfile?.()||{},user=window.GraviSupabase?.getUser?.()||{};return {userId:user.id||"",user:profile.full_name||user.email||"Usuario GRAVI SST",role:profile.role||"Sin rol"};}
function auditContext(){return {online:navigator.onLine,width:innerWidth,height:innerHeight,platform:navigator.platform||"",userAgent:navigator.userAgent||""};}
function auditLog(action,module,relatedId="",workId=activeId,extra={}){data.auditLog||=[];const actor=auditUser(),work=workId?workById(workId):activeWork(),entry={id:uid(),at:new Date().toISOString(),date:today(),userId:actor.userId,user:actor.user,role:actor.role,action,module,relatedId,workId:workId||"",development:work?.development||extra.development||"",workName:work?.name||extra.workName||"",context:auditContext(),...extra};data.auditLog.unshift(entry);data.auditLog=data.auditLog.slice(0,1000);save();return entry;}
window.GraviAudit={log:auditLog};
function auditNavButtonMarkup(){return '<button type="button" data-nav52="auditLog"><span class="nav-icon"><svg><use href="#nav-history"/></svg></span><span class="nav-label">Bitacora</span></button>';}
function installAuditNavigation(){const admin=q('[data-nav52="administration"]');if(admin&&!q('.nav-global-only [data-nav52="auditLog"]'))admin.insertAdjacentHTML("beforebegin",auditNavButtonMarkup());const histories=q('[data-phase3-nav="histories"]');if(histories&&!q('.nav-work-only [data-nav52="auditLog"]'))histories.insertAdjacentHTML("afterend",auditNavButtonMarkup());}
function visibleAuditEntries(){const entries=data.auditLog||[],actor=auditUser();if(window.GraviSupabase?.can?.("admin-write"))return entries;if(window.GraviSupabase?.can?.("field-write"))return entries.filter(item=>item.userId===actor.userId||(activeId&&item.workId===activeId));return entries.filter(item=>item.userId===actor.userId);}
function moduleClassForAudit(module){const value=normalized(module);if(value.includes("acceso"))return"sem-green";if(value.includes("pdf")||value.includes("evidencia"))return"sem-yellow";if(value.includes("obra")||value.includes("desarrollo"))return"sem-orange";if(value.includes("usuario"))return"sem-red";return"sem-gray";}
function renderAuditRows(list){return list.length?`<div class="audit-list">${list.map(item=>`<article class="audit-row"><span class="semaphore ${moduleClassForAudit(item.module)}"></span><div><strong>${esc(item.action)}</strong><small>${esc(item.module)}${item.relatedId?` · ${esc(item.relatedId)}`:""}</small></div><div><b>${esc(item.user)}</b><small>${esc(item.role)}</small></div><div><b>${esc(item.workName||"Sin obra")}</b><small>${esc(item.development||"Sin desarrollo")}</small></div><time>${fmt((item.at||"").slice(0,10))}<small>${esc((item.at||"").slice(11,16))}</small></time></article>`).join("")}</div>`:'<div class="empty-management">No hay actividad registrada con esos filtros.</div>';}
function renderAuditLog(){q("#managementTitle").textContent="Bitacora";q("#managementSubtitle").textContent="Actividad operativa registrada automaticamente";q("#managementActions").innerHTML="";const entries=visibleAuditEntries();const modules=[...new Set(entries.map(item=>item.module).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"es"));q("#managementContent").innerHTML=`<div class="audit-toolbar"><label>Buscar<input id="auditSearch" type="search" placeholder="Usuario, accion, obra..."></label><label>Modulo<select id="auditModule"><option value="">Todos</option>${modules.map(module=>`<option>${esc(module)}</option>`).join("")}</select></label><label>Fecha<input id="auditDate" type="date"></label></div><div id="auditResults">${renderAuditRows(entries.slice(0,120))}</div>`;const apply=()=>{const term=normalized(q("#auditSearch").value),module=q("#auditModule").value,date=q("#auditDate").value,filtered=entries.filter(item=>(!module||item.module===module)&&(!date||(item.at||"").slice(0,10)===date)&&(!term||normalized([item.user,item.role,item.action,item.module,item.workName,item.development,item.relatedId].join(" ")).includes(term)));q("#auditResults").innerHTML=renderAuditRows(filtered.slice(0,160));};["#auditSearch","#auditModule","#auditDate"].forEach(selector=>q(selector).addEventListener("input",apply));displayView("managementView");qa(".sidebar-nav button").forEach(button=>button.classList.remove("active"));qa('[data-nav52="auditLog"]').forEach(button=>button.classList.add("active"));if(hasWorkContext52())setWorkBreadcrumb52("Bitacora");else setBreadcrumb52([{label:"Inicio",action:()=>renderDevelopments52(true)},{label:"Bitacora"}]);}
