function workDashboardMetrics54(){const records=appRecords(),daily=currentDailyLog54(),openIncidents=records.filter(record=>record.type==="incident"&&record.status!=="Cerrado").length;return [{key:"workers",value:presentCount(activeId,today()),label:"Trabajadores presentes",meta:"Asistencia de hoy"},{key:"contractors",value:contractors().filter(item=>isActiveStatus(item.status)).length,label:"Contratistas activos",meta:"Empresas en obra"},{key:"visitors",value:visitors().filter(item=>item.date===today()).length,label:"Visitantes del dia",meta:"Accesos registrados"},{key:"pending",value:mobilePendingInspections53(),label:"Inspecciones pendientes",meta:"Programadas sin ejecutar",attention:mobilePendingInspections53()>0},{key:"incidents",value:openIncidents,label:"Incidentes abiertos",meta:"Seguimiento requerido",attention:openIncidents>0},{key:"accidents",value:investigations().length,label:"Accidentes",meta:"Investigaciones"},{key:"evidence",value:evidenceToday54(records),label:"Evidencia del dia",meta:"Fotos y anexos"},{key:"docs",value:expiringDocuments54(),label:"Docs por vencer",meta:"Proximos 30 dias",attention:expiringDocuments54()>0}];}
