function recentWorkTimeline54(){const daily=(typeof dailyLogsForWork==="function"?dailyLogsForWork():[]).filter(item=>item.status==="Cerrado").map(item=>({at:item.closedAt||`${item.date}T18:00`,activity:"Registro diario cerrado",user:item.supervisor||"Supervisor"})),quick=(data.quickObservations||[]).filter(item=>item.workId===activeId).map(item=>({at:item.createdAt||item.capturedAt,activity:`${item.category||"Observacion"}: ${item.text||"Sin detalle"}`,user:"Captura rapida"}));return [...recentActivities(activeId),...daily,...quick].filter(item=>item.at).sort((a,b)=>(b.at||"").localeCompare(a.at||"")).slice(0,8);}
