function workAttendanceSummary56(){const rec=data.attendance[attendanceKey(today())]||{},values=Object.values(rec).map(value=>normalized(value)),registered=workers().filter(worker=>isActiveStatus(worker.status)).length,present=Object.values(rec).filter(value=>value==="P").length,permits=values.filter(value=>value.includes("permiso")).length,disabled=values.filter(value=>value.includes("incap")).length;return {registered,present,absent:Math.max(0,registered-present-permits-disabled),permits,disabled,visitors:visitors().filter(item=>item.date===today()).length};}
function workInspectionSummary56(records){const scheduled=(data.scheduledActivities||[]).filter(task=>task.workId===activeId),pending=scheduled.filter(task=>!task.executedDate).length,done=records.filter(record=>record.type!=="incident").length,overdue=scheduled.filter(task=>!task.executedDate&&task.scheduledDate&&task.scheduledDate<today()).length,total=Math.max(1,done+pending+overdue);return {scheduled:scheduled.length,done,pending,overdue,total};}
