function overallState56(stats,inspection,incidents,weather){const reasons=[];let level="normal",title="Operacion normal";if(stats.general<75||incidents.open>3||inspection.overdue>0){level="attention";title="Requiere atencion";}if(stats.general<55||incidents.accidents>0&&incidents.open>5){level="critical";title="Critico";}reasons.push(`Cumplimiento ${stats.general}%`);reasons.push(incidents.accidents?`${incidents.accidents} accidentes registrados`:"Sin accidentes incapacitantes");reasons.push(inspection.pending?`${inspection.pending} inspecciones pendientes`:"Inspecciones al dia");reasons.push(weather.heat?`WBGT: ${weather.heat}`:"Clima sin alerta registrada");return {level,title,reasons};}
